mapper.select:
select id,log_type,module_name,biz_type,biz_id,operation_type,operation_desc,
       operator_id,operator_name,request_uri,request_method,ip_address,
       success_flag,error_message,operate_time
from sys_oper_log


        and lopg_type=#{q.logType}


        and module_name like concat('%',#{q.moduleName},'%')


        and operation_type=#{q.operationType}


        and operator_name like concat('%',#{q.operatorName},'%')


        and success_flag=#{q.successFlag}


        and operate_time >=#{q.beginTime}


        and operate_time <=#{q.endTime}


order by operate_time desc
